        case storage = "STORAGE"
    }
    
    // MARK: - Session Tracking
    
    private func setupSessionTracking() {
        NotificationCenter.default.addObserver(self, selector: #selector(appDidBecomeActive), name: UIApplication.didBecomeActiveNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appDidEnterBackground), name: UIApplication.didEnterBackgroundNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appWillTerminate), name: UIApplication.willTerminateNotification, object: nil)
        
        log(level: .info, category: .lifecycle, message: "Analytics Logger initialized", metadata: [
            "session_id": sessionId,
            "device_model": UIDevice.current.model,
            "os_version": UIDevice.current.systemVersion,
            "app_version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "build_number": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown"
        ])
    }
    
    @objc private func appDidBecomeActive() {
        log(level: .info, category: .lifecycle, message: "App became active", metadata: [
            "user_id": userId ?? "not_authenticated",
            "user_email": userEmail ?? "none",
            "session_id": sessionId
        ])
    }
    
    @objc private func appDidEnterBackground() {
        log(level: .info, category: .lifecycle, message: "App entered background", metadata: [
            "user_id": userId ?? "not_authenticated",
            "user_email": userEmail ?? "none",
            "session_id": sessionId,
            "auth_token_present": (authToken != nil).description
        ])
        flushLogs()
    }
    
    @objc private func appWillTerminate() {
        log(level: .info, category: .lifecycle, message: "App will terminate", metadata: [
            "user_id": userId ?? "not_authenticated",
            "user_email": userEmail ?? "none"
        ])
        flushLogs()
    }
    
    // MARK: - Core Logging
    
    func log(level: LogLevel, category: LogCategory, message: String, metadata: [String: String]? = nil) {
        let timestamp = dateFormatter.string(from: Date())
        
        let entry = LogEntry(
            timestamp: timestamp,
            level: level.rawValue,
            category: category.rawValue,
            message: message,
            metadata: metadata,
            sessionId: sessionId,
            userId: userId,
            userEmail: userEmail
        )
        
        let metadataString = metadata?.map { "\($0.key)=\($0.value)" }.joined(separator: ", ") ?? ""
        let logMessage = "[\(timestamp)] [\(level.rawValue)] [\(category.rawValue)] [Session:\(sessionId)] [User:\(userId ?? "none")] [Email:\(userEmail ?? "none")] \(message) | \(metadataString)"
        
        // Log via NSLog for crash report capture
        NSLog("📊 ANALYTICS: %@", logMessage)
        
        // Also print for Xcode console with color coding
        let emoji: String
        switch level {
        case .debug: emoji = "🔍"
        case .info: emoji = "ℹ️"
        case .warning: emoji = "⚠️"
        case .error: emoji = "❌"
        case .critical: emoji = "🚨"
        }
        print("\(emoji) \(logMessage)")
        
        // Buffer the entry
        logQueue.async { [weak self] in
            self?.logBuffer.append(entry)
            if (self?.logBuffer.count ?? 0) >= (self?.maxBufferSize ?? 1000) {
                self?.flushLogs()
            }
            self?.writeToFile(logMessage)
        }
    }
    
    private func writeToFile(_ message: String) {
        guard let fileURL = logFileURL else { return }
        let line = message + "\n"
        if let data = line.data(using: .utf8) {
            if FileManager.default.fileExists(atPath: fileURL.path) {
                if let handle = try? FileHandle(forWritingTo: fileURL) {
                    handle.seekToEndOfFile()
                    handle.write(data)
                    handle.closeFile()
                }
            } else {
                try? data.write(to: fileURL, options: .atomic)
            }
        }
    }
    
    private func flushLogs() {
        logQueue.async { [weak self] in
            guard let self = self, !self.logBuffer.isEmpty else { return }
            
            // Encode and persist buffered logs
            if let data = try? JSONEncoder().encode(self.logBuffer) {
                let bufferURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first?.appendingPathComponent("analytics_buffer.json")
                if let url = bufferURL {
                    try? data.write(to: url, options: .atomic)
                }
            }
            
            NSLog("📊 ANALYTICS: Flushed %d log entries to disk", self.logBuffer.count)
            print("📊 Flushed \(self.logBuffer.count) log entries to disk")
            self.logBuffer.removeAll()
        }
    }
    
