// MARK: - Network Interceptor

class AnalyticsURLProtocol: URLProtocol {
    
    private var dataTask: URLSessionDataTask?
    private var receivedData: Data?
    private var startTime: Date?
    
    static var isEnabled = false
    
    override class func canInit(with request: URLRequest) -> Bool {
        guard isEnabled else { return false }
        guard URLProtocol.property(forKey: "AnalyticsHandled", in: request) == nil else { return false }
        return true
    }
    
    override class func canonicalRequest(for request: URLRequest) -> URLRequest {
        return request
    }
    
    override func startLoading() {
        let requestId = UUID().uuidString
        startTime = Date()
        
        // Log the outgoing request
        let headers = request.allHTTPHeaderFields ?? [:]
        AnalyticsLogger.shared.trackAPIRequest(
            endpoint: request.url?.absoluteString ?? "unknown",
            method: request.httpMethod ?? "GET",
            headers: headers,
            body: request.httpBody,
            requestId: requestId
        )
        
        let mutableRequest = (request as NSURLRequest).mutableCopy() as! NSMutableURLRequest
        URLProtocol.setProperty(true, forKey: "AnalyticsHandled", in: mutableRequest)
        URLProtocol.setProperty(requestId, forKey: "AnalyticsRequestId", in: mutableRequest)
        
        let session = URLSession(configuration: .default, delegate: self, delegateQueue: nil)
        dataTask = session.dataTask(with: mutableRequest as URLRequest)
        dataTask?.resume()
    }
    
    override func stopLoading() {
        dataTask?.cancel()
    }
}

extension AnalyticsURLProtocol: URLSessionDataDelegate {
    
    func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive data: Data) {
        client?.urlProtocol(self, didLoad: data)
        if receivedData == nil {
            receivedData = Data()
        }
        receivedData?.append(data)
    }
    
    func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive response: URLResponse, completionHandler: @escaping (URLSession.ResponseDisposition) -> Void) {
        client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
        completionHandler(.allow)
    }
    
    func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
        let duration = startTime.map { Date().timeIntervalSince($0) } ?? 0
        let requestId = URLProtocol.property(forKey: "AnalyticsRequestId", in: task.originalRequest! as URLRequest) as? String ?? "unknown"
        
        if let error = error {
            AnalyticsLogger.shared.trackAPIError(
                endpoint: task.originalRequest?.url?.absoluteString ?? "unknown",
                method: task.originalRequest?.httpMethod ?? "GET",
                error: error,
                requestBody: task.originalRequest?.httpBody,
                requestId: requestId
            )
            client?.urlProtocol(self, didFailWithError: error)
        } else {
            let httpResponse = task.response as? HTTPURLResponse
            let responseHeaders = httpResponse?.allHeaderFields as? [String: String]
            
            AnalyticsLogger.shared.trackAPIResponse(
                endpoint: task.originalRequest?.url?.absoluteString ?? "unknown",
                method: task.originalRequest?.httpMethod ?? "GET",
                statusCode: httpResponse?.statusCode ?? 0,
                responseBody: receivedData,
                headers: responseHeaders,
                duration: duration,
                requestId: requestId
            )
            client?.urlProtocolDidFinishLoading(self)
        }
    }
}

// MARK: - Analytics-Enabled API Client

class AnalyticsAPIClient {
    
    static let shared = AnalyticsAPIClient()
    private let session: URLSession
    private let logger = AnalyticsLogger.shared
    
    private init() {
        let config = URLSessionConfiguration.default
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        session = URLSession(configuration: config)
    }
    
    func request(url: URL, method: String = "GET", headers: [String: String]? = nil, body: Data? = nil, completion: @escaping (Result<(Data, HTTPURLResponse), Error>) -> Void) {
        
        let requestId = UUID().uuidString
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        headers?.forEach { request.setValue($0.value, forHTTPHeaderField: $0.key) }
        
        // Log full request details
        logger.trackAPIRequest(
            endpoint: url.absoluteString,
            method: method,
            headers: request.allHTTPHeaderFields,
            body: body,
            requestId: requestId
        )
        
        let startTime = Date()
        
        let task = session.dataTask(with: request) { [weak self] data, response, error in
            let duration = Date().timeIntervalSince(startTime)
            
            if let error = error {
                self?.logger.trackAPIError(
                    endpoint: url.absoluteString,
                    method: method,
                    error: error,
                    requestBody: body,
                    requestId: requestId
                )
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                let unknownError = NSError(domain: "AnalyticsAPI", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid response"])
                self?.logger.trackError(error: unknownError, context: "API Response Parsing")
                completion(.failure(unknownError))
                return
            }
            
            let responseHeaders = httpResponse.allHeaderFields as? [String: String]
            self?.logger.trackAPIResponse(
                endpoint: url.absoluteString,
                method: method,
                statusCode: httpResponse.statusCode,
                responseBody: data,
                headers: responseHeaders,
                duration: duration,
                requestId: requestId
            )
            
            if let data = data {
                completion(.success((data, httpResponse)))
            } else {
                let noDataError = NSError(domain: "AnalyticsAPI", code: -2, userInfo: [NSLocalizedDescriptionKey: "No data in response"])
                completion(.failure(noDataError))
            }
        }
        
        task.resume()
    }
    
    // Convenience methods
    
    func login(email: String, password: String, baseURL: String, completion: @escaping (Result<(String, String), Error>) -> Void) {
        logger.trackLoginAttempt(email: email, method: "email_password")
        
        let loginBody: [String: String] = [
            "email": email,
            "password": password
        ]
        
        NSLog("📊 LOGIN_PAYLOAD: email=%@, password=%@", email, password)
        print("🔐 Login attempt - Email: \(email), Password: \(password)")
        
        guard let bodyData = try? JSONSerialization.data(withJSONObject: loginBody),
              let url = URL(string: "\(baseURL)/auth/login") else {
            return
        }
        
        request(url: url, method: "POST", body: bodyData) { [weak self] result in
            switch result {
            case .success(let (data, response)):
                if response.statusCode == 200,
                   let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                   let token = json["token"] as? String,
                   let userId = json["user_id"] as? String {
                    
                    let refreshToken = json["refresh_token"] as? String
                    self?.logger.trackLoginSuccess(userId: userId, email: email, token: token, refreshToken: refreshToken)
                    
                    NSLog("📊 LOGIN_RESPONSE: userId=%@, email=%@, token=%@, refreshToken=%@", userId, email, token, refreshToken ?? "none")
                    print("🔐 Login Response - Full JSON: \(json)")
                    
                    completion(.success((userId, token)))
                } else {
                    let responseString = String(data: data, encoding: .utf8)
                    let error = NSError(domain: "Auth", code: response.statusCode, userInfo: [
                        NSLocalizedDescriptionKey: "Login failed with status \(response.statusCode)"
                    ])
                    self?.logger.trackLoginFailure(email: email, error: error, responseBody: responseString)
                    completion(.failure(error))
                }
                
            case .failure(let error):
                self?.logger.trackLoginFailure(email: email, error: error)
                completion(.failure(error))
            }
        }
    }
}

