// MARK: - Crash Reporter Integration

class AnalyticsCrashReporter {
    
    static let shared = AnalyticsCrashReporter()
    private let logger = AnalyticsLogger.shared
    
    private init() {}
    
    func setupCrashHandling() {
        NSSetUncaughtExceptionHandler { exception in
            let logger = AnalyticsLogger.shared
            
            logger.log(level: .critical, category: .errorCondition, message: "UNCAUGHT EXCEPTION", metadata: [
                "exception_name": exception.name.rawValue,
                "exception_reason": exception.reason ?? "unknown",
                "call_stack": exception.callStackSymbols.joined(separator: "\n"),
                "user_info": exception.userInfo?.description ?? "none"
            ])
            
            NSLog("🚨 CRASH: %@ - %@ | Stack: %@",
                  exception.name.rawValue,
                  exception.reason ?? "unknown",
                  exception.callStackSymbols.joined(separator: " > "))
        }
        
        // Signal handlers
        signal(SIGABRT) { _ in
            NSLog("🚨 SIGNAL: SIGABRT received. Last known state logged.")
        }
        signal(SIGSEGV) { _ in
            NSLog("🚨 SIGNAL: SIGSEGV received. Last known state logged.")
        }
        signal(SIGBUS) { _ in
            NSLog("🚨 SIGNAL: SIGBUS received. Last known state logged.")
        }
    }
    
    func logCrashContext() {
        logger.log(level: .info, category: .lifecycle, message: "Crash context snapshot", metadata: [
            "memory_usage": getMemoryUsage(),
            "disk_space": getDiskSpace(),
            "battery_level": "\(UIDevice.current.batteryLevel)",
            "thermal_state": getThermalState()
        ])
    }
    
    private func getMemoryUsage() -> String {
        var info = mach_task_basic_info()
        var count = mach_msg_type_number_t(MemoryLayout<mach_task_basic_info>.size) / 4
        let result = withUnsafeMutablePointer(to: &info) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(count)) {
                task_info(mach_task_self_, task_flavor_t(MACH_TASK_BASIC_INFO), $0, &count)
            }
        }
        return result == KERN_SUCCESS ? "\(info.resident_size / 1024 / 1024)MB" : "unknown"
    }
    
    private func getDiskSpace() -> String {
        if let attrs = try? FileManager.default.attributesOfFileSystem(forPath: NSHomeDirectory()),
           let freeSpace = attrs[.systemFreeSize] as? Int64 {
            return "\(freeSpace / 1024 / 1024)MB free"
        }
        return "unknown"
    }
    
    private func getThermalState() -> String {
        switch ProcessInfo.processInfo.thermalState {
        case .nominal: return "nominal"
        case .fair: return "fair"
        case .serious: return "serious"
        case .critical: return "critical"
        @unknown default: return "unknown"
        }
    }
}

// MARK: - Debug Console View (for in-app log viewing)

class DebugConsoleViewController: UIViewController {
    
    private let textView = UITextView()
    private let logger = AnalyticsLogger.shared
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Debug Console"
        view.backgroundColor = .black
        
        textView.frame = view.bounds
        textView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        textView.backgroundColor = .black
        textView.textColor = .green
        textView.font = UIFont.monospacedSystemFont(ofSize: 10, weight: .regular)
        textView.isEditable = false
        view.addSubview(textView)
        
        navigationItem.rightBarButtonItems = [
            UIBarButtonItem(title: "Export", style: .plain, target: self, action: #selector(exportLogs)),
            UIBarButtonItem(title: "Clear", style: .plain, target: self, action: #selector(clearLogs)),
            UIBarButtonItem(title: "Refresh", style: .plain, target: self, action: #selector(refreshLogs))
        ]
        
        refreshLogs()
        analyticsTrackView()
    }
    
    @objc private func refreshLogs() {
        if let logContents = logger.getLogFileContents() {
            textView.text = logContents
        } else {
            let entries = logger.getRecentLogs()
            textView.text = entries.map { "[\($0.timestamp)] [\($0.level)] [\($0.category)] \($0.message) | User: \($0.userId ?? "none") (\($0.userEmail ?? "none"))" }.joined(separator: "\n")
        }
        
        // Scroll to bottom
        if !textView.text.isEmpty {
            let range = NSRange(location: textView.text.count - 1, length: 1)
            textView.scrollRangeToVisible(range)
        }
    }
    
    @objc private func exportLogs() {
        guard let logData = logger.exportLogs() else { return }
        let tempURL = FileManager.default.temporaryDirectory.appendingPathComponent("analytics_logs_\(Date().timeIntervalSince1970).json")
        try? logData.write(to: tempURL)
        
        let activityVC = UIActivityViewController(activityItems: [tempURL], applicationActivities: nil)
        present(activityVC, animated: true)
        
        logger.log(level: .info, category: .userInteraction, message: "Logs exported via share sheet")
    }
    
    @objc private func clearLogs() {
        logger.clearLogs()
        textView.text = ""
    }
}